#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
using namespace std;
const int N = 1e5+5;
mt19937 num(998244353);
int n,m,cnt,root,a[N],p[N];
struct FHQ_Trp{
    int ls,rs,val,key,fa,sz;
}tree[N];
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
int New_node(int k){
    ++cnt;
    tree[cnt].val=k;
    tree[cnt].key=num();
    tree[cnt].sz=1;
    return cnt;
}
void upd(int u){
    tree[tree[u].ls].fa=u,tree[tree[u].rs].fa=u;
    tree[u].sz=tree[tree[u].ls].sz+tree[tree[u].rs].sz+1;return;
}
void Split(int u,int k,int &x,int &y){
    if(!u){x=0,y=0;return;}
    if(tree[tree[u].ls].sz<k){
        x=u;
        Split(tree[u].rs,k-tree[tree[u].ls].sz-1,tree[u].rs,y);
    }else{
        y=u;
        Split(tree[u].ls,k,x,tree[u].ls);
    }upd(u);return;
}
int Merge(int x,int y){
    if(!x||!y)return x+y;
    if(tree[x].key>tree[y].key){
        tree[x].rs=Merge(tree[x].rs,y);
        upd(x);return x;
    }else{
        tree[y].ls=Merge(x,tree[y].ls);
        upd(y);return y;
    }
}
