int Get_rank(int x){
    int rk=tree[tree[x].ls].sz+1;
    while(tree[x].fa){
        if(x==tree[tree[x].fa].rs)
            rk+=tree[tree[tree[x].fa].ls].sz+1;
        x=tree[x].fa;
    }return rk;
}
int main(){
    n=read(),m=read();
    for(int i=1;i<=n;i++)a[i]=read();
    for(int i=1;i<=n;i++)
        p[a[i]]=New_node(a[i]),
        root=Merge(root,p[a[i]]);
    for(int i=1;i<=m;i++){
        string opt;cin>>opt;
        if(opt=="Top"){
            int u=read(),rk=Get_rank(p[u]);
            int x=0,y=0,z=0;
            Split(root,rk-1,x,y);
            Split(y,1,y,z);
            root=Merge(Merge(y,x),z);
        }else if(opt=="Bottom"){
            int u=read(),rk=Get_rank(p[u]);
            int x=0,y=0,z=0;
            Split(root,rk-1,x,y);
            Split(y,1,y,z);
            root=Merge(Merge(x,z),y);
        }else if(opt=="Insert"){
            int u=read(),t=read();
            if(!t)continue;
            int rk=Get_rank(p[u]);
            int x=0,y=0,z=0;
            Split(root,rk-1,x,y);
            Split(y,1,y,z);
            if(t==1){
                int A=0,B=0;Split(z,1,A,B);
                root=Merge(Merge(Merge(x,A),y),B);
            }else{
                int A=0,B=0;Split(x,rk-2,A,B);
                root=Merge(Merge(Merge(A,y),B),z);
            }
        }else if(opt=="Ask"){
            int u=read();
            cout<<Get_rank(p[u])-1<<"\n";
        }else{
            int u=read();
            int x=0,y=0,z=0;
            Split(root,u-1,x,y);
            Split(y,1,y,z);
            cout<<tree[y].val<<"\n";
            root=Merge(Merge(x,y),z);
        }
    }
    return 0;
}
